                                const isEditingThis = editingSfxIndex === idx; 
                                const hasFile = sfx && sfx.url;
                                const hasGain = sfx && sfx.customGain !== 1.0;
                                const hasCuts = sfx && ((sfx.trimStart && sfx.trimStart > 0) || (sfx.trimEnd && sfx.trimEnd > 0));
