      {!isPinnedDesktop && (
          <ChatModal 
              isOpen={isChatOpen} 
              messages={chatMessages}
              onSendMessage={handleSendChatMessage}
              onEndCall={handleEndCall}
              onCloseWindow={handleCloseChatWindow} // NEW PROP PASSED
              t={t}
              isPinned={chatPinned}
              onTogglePin={(val) => setChatPinned(val)}
              displayMode="floating"
