import { useState, useEffect, useRef, useCallback } from 'react';
import { PlayerState, Song, SfxItem } from '../types';
import { shouldReloadAudioSource } from '../utils/platformUtils';

interface UseAudioPlayerProps {
    targetItem: Song | SfxItem | null;
    playbackSource: 'html5' | 'waveform';
    onTrackEnd: () => void;
    isAndroid: boolean; 
}

export const useAudioPlayer = ({ 
    targetItem, 
    playbackSource, 
    onTrackEnd,
    isAndroid 
}: UseAudioPlayerProps) => {

    // --- STATE ---
    const [state, setState] = useState<PlayerState>({
        isPlaying: false,
        currentTime: 0,
        duration: 0,
        volume: 1,
        isFading: false // NEW
    });

    // --- REFS ---
    const audioRef = useRef<HTMLAudioElement | null>(null);
    const volumeRef = useRef<number>(1.0); 
    const fadeIntervalRef = useRef<any>(null);
    const isHandlingEndRef = useRef(false); // NEW: Debounce lock for track end

    // Track ID to detect changes even if URL is same
    const currentTrackIdRef = useRef<string | null>(null);

    // NEW: Callback Ref to prevent stale closures
    const onTrackEndRef = useRef(onTrackEnd);
    useEffect(() => { onTrackEndRef.current = onTrackEnd; }, [onTrackEnd]);

    // --- INITIALIZATION ---
    useEffect(() => {
        audioRef.current = new Audio();
        return () => {
            if (audioRef.current) {
                audioRef.current.pause();
                audioRef.current.src = "";
            }
            if (fadeIntervalRef.current) clearInterval(fadeIntervalRef.current);
        };
    }, []);

    // --- INTERNAL HANDLER (Memoized) ---
    const handleTrackEndInternal = useCallback(() => {
        // PREVENT DOUBLE FIRING: Lock execution for 500ms
        if (isHandlingEndRef.current) return;
        isHandlingEndRef.current = true;
        setTimeout(() => { isHandlingEndRef.current = false; }, 500);

        setState(prev => ({ ...prev, isPlaying: false, isFading: false }));
        if (audioRef.current) audioRef.current.pause();
        if (fadeIntervalRef.current) clearInterval(fadeIntervalRef.current);

        // Always call the freshest callback from App.tsx
        if (onTrackEndRef.current) onTrackEndRef.current();
    }, []);

    // --- SOURCE LOADING MANAGEMENT ---
    useEffect(() => {
        const audio = audioRef.current;
        if (!audio) return;

        if (targetItem && targetItem.url) {
            // 1. Detect if it's logically a new track (ID changed)
            const hasTrackChanged = targetItem.id !== currentTrackIdRef.current;

            // 2. Detect if technical source needs reload
            const currentSrc = audio.src;
            const needsReload = shouldReloadAudioSource(currentSrc, targetItem.url);

            if (needsReload) {
                audio.src = targetItem.url;
                // Preload metadata to ensure duration is available
                audio.preload = 'metadata'; 
            }

            // 3. Reset Position/State if track changed OR source reloaded
            if (hasTrackChanged || needsReload) {
                currentTrackIdRef.current = targetItem.id;

                // === FORCE SEEK TO MARK IN (TRIMSTART) ===
                const start = targetItem.trimStart || 0;
                audio.currentTime = start;

                setState(prev => ({ 
                    ...prev, 
                    currentTime: start,
                    // If reloading, duration might be 0 until metadata loads, but we reset it to avoid stale duration
                    duration: needsReload ? 0 : prev.duration,
                    isFading: false
                }));

                // Reset Volume for new track (unless we want to persist global volume, but usually per-track gain applies)
                if (!state.isPlaying) {
                    const initialVol = targetItem.customGain || 1.0;
                    audio.volume = initialVol;
                    volumeRef.current = initialVol;
                    setState(prev => ({ ...prev, volume: initialVol }));
                }
            } else {
                // If track ID is same and Source is same (e.g. editing parameters live), just ensure volume matches if not playing
                if (!state.isPlaying && targetItem.customGain !== undefined) {
                     audio.volume = targetItem.customGain;
                     volumeRef.current = targetItem.customGain;
                }
            }
        } else {
            // No target
            audio.src = "";
            currentTrackIdRef.current = null;
            setState(prev => ({ ...prev, currentTime: 0, duration: 0, isFading: false }));
        }
    }, [targetItem, state.isPlaying, playbackSource]); 

    // --- PLAYBACK CONTROL LOOP ---
    useEffect(() => {
        const audio = audioRef.current;
        if (!audio) return;

        if (playbackSource === 'html5') {
            if (state.isPlaying && audio.paused) {
                const start = targetItem?.trimStart || 0;
                // Sanity check: if we are way before start, jump to start
                if (audio.currentTime < start - 0.1) {
                    audio.currentTime = start;
                }

                audio.play().catch(e => {
                    console.error("Audio Play Error:", e);
                    setState(prev => ({ ...prev, isPlaying: false }));
                });
            } else if (!state.isPlaying && !audio.paused) {
                audio.pause();
            }
        } else {
            // Waveform mode: mute HTML5 audio or pause it
            if (!audio.paused) {
                audio.pause();
            }
        }
    }, [state.isPlaying, playbackSource, targetItem]);

    // --- TIME UPDATE & AUTO FADE ---
    useEffect(() => {
        const audio = audioRef.current;
        if (!audio) return;

        const updateState = () => {
            if (playbackSource === 'html5') {
                const t = audio.currentTime;

                if (targetItem) {
                    const start = targetItem.trimStart || 0;
                    const end = (targetItem.trimEnd && targetItem.trimEnd > 0) ? targetItem.trimEnd : audio.duration;

                    // CUSTOM FADE DURATION OR DEFAULT 3s
                    const fadeDuration = targetItem.fadeOutDuration || 3; 

                    // 1. Check End
                    if (t >= end - 0.05) {
                        handleTrackEndInternal();
                        return;
                    }

                    // 2. Auto Fade Out
                    if (targetItem.hasFadeOut && end > 0) {
                        const remaining = end - t;
                        const baseVol = volumeRef.current; 

                        if (remaining <= fadeDuration && remaining > 0) {
                            const factor = remaining / fadeDuration; 
                            audio.volume = baseVol * factor;
                        }
                    }
                }

                setState(prev => ({
                    ...prev,
                    currentTime: t,
                    duration: audio.duration || 0
                }));
            }
        };

        const handleEnded = () => {
            if (playbackSource === 'html5') {
                handleTrackEndInternal();
            }
        };

        // Standard events
        audio.addEventListener('timeupdate', updateState);
        audio.addEventListener('loadedmetadata', updateState);
        audio.addEventListener('ended', handleEnded);

        return () => {
            audio.removeEventListener('timeupdate', updateState);
            audio.removeEventListener('loadedmetadata', updateState);
            audio.removeEventListener('ended', handleEnded);
        };
    }, [playbackSource, targetItem, handleTrackEndInternal]);

    // --- EXPOSED CONTROLS ---

    const play = useCallback(() => {
        setState(prev => ({ ...prev, isPlaying: true }));
    }, []);

    const pause = useCallback(() => {
        setState(prev => ({ ...prev, isPlaying: false, isFading: false }));
        if (fadeIntervalRef.current) clearInterval(fadeIntervalRef.current);
    }, []);

    const stop = useCallback(() => {
        setState(prev => ({ ...prev, isPlaying: false, isFading: false }));
        if (fadeIntervalRef.current) clearInterval(fadeIntervalRef.current);

        if(audioRef.current) {
            audioRef.current.pause();
            if(targetItem) {
                const resetVol = targetItem.customGain || 1.0;
                audioRef.current.volume = resetVol;
                volumeRef.current = resetVol;

                // === RESET TO MARK IN (TRIMSTART) ===
                const start = targetItem.trimStart || 0;
                audioRef.current.currentTime = start;
                setState(prev => ({...prev, volume: resetVol, currentTime: start}));
            } else {
                audioRef.current.currentTime = 0;
                setState(prev => ({...prev, currentTime: 0}));
            }
        }
        return (targetItem && targetItem.trimStart) ? targetItem.trimStart : 0;
    }, [targetItem]);

    const seek = useCallback((time: number) => {
        if (targetItem) {
            let target = time;
            const start = targetItem.trimStart || 0;
            const end = (targetItem.trimEnd && targetItem.trimEnd > 0) ? targetItem.trimEnd : (state.duration || 100);
            // Clamp
            target = Math.max(start, Math.min(end, time));

            setState(prev => ({ ...prev, currentTime: target }));
            if (audioRef.current) audioRef.current.currentTime = target;
        }
    }, [targetItem, state.duration]);

    const setVolume = useCallback((vol: number) => {
        const clamped = Math.max(0, Math.min(1, vol));
        volumeRef.current = clamped;
        setState(prev => ({ ...prev, volume: clamped }));
        if (audioRef.current) {
            audioRef.current.volume = clamped; 
        }
    }, []);

    const manualFade = useCallback((durationMs: number = 2500) => {
        const audio = audioRef.current;
        if (!audio || audio.paused) return;

        if (fadeIntervalRef.current) clearInterval(fadeIntervalRef.current);

        // SET FADING STATE
        setState(prev => ({ ...prev, isFading: true }));

        const fadeDuration = durationMs; 
        const stepTime = 50; 
        const steps = fadeDuration / stepTime;
        const volStep = audio.volume / steps;

        fadeIntervalRef.current = setInterval(() => {
            if (audio.volume > 0.02) {
                audio.volume = Math.max(0, audio.volume - volStep);
            } else {
                audio.volume = 0;
                audio.pause();
                clearInterval(fadeIntervalRef.current);
                // RESET FADING STATE
                setState(prev => ({...prev, isPlaying: false, volume: 0, isFading: false}));
                volumeRef.current = 0;
                handleTrackEndInternal();
            }
        }, stepTime);
    }, [handleTrackEndInternal]);

    const updateState = useCallback((updates: Partial<PlayerState>) => {
        setState(prev => ({ ...prev, ...updates }));
    }, []);

    const hardReset = useCallback(() => {
        if (fadeIntervalRef.current) clearInterval(fadeIntervalRef.current);
        isHandlingEndRef.current = false; // Reset lock
        if(audioRef.current) {
            audioRef.current.pause();
            audioRef.current.currentTime = 0;
        }
        currentTrackIdRef.current = null; // Force reset ID tracking
        setState(prev => ({ ...prev, isPlaying: false, currentTime: 0, isFading: false }));
    }, []);

    return {
        state,
        controls: {
            play,
            pause,
            stop,
            seek,
            setVolume,
            manualFade,
            updateState,
            hardReset
        },
        audioRef
    };
};

import React from 'react';
import { Play, Pause, SkipBack, SkipForward, Volume2, VolumeX, Wind, Square, Settings } from 'lucide-react';
import { PlayerState, AppMode, Language } from '../types';
import { translations } from '../translations';

interface PlayerControlsProps {
  state: PlayerState;
  onPlayPause: () => void;
  onNext: () => void;
  onPrev: () => void;
  onStop: () => void; 
  onSeek: (time: number) => void;
  onVolumeChange: (vol: number) => void;
  onFade: () => void;
  onFadeConfig?: () => void;
  manualFadeDuration?: number; // NEW PROP
  title: string;
  startTime: number;
  endTime: number;
  appMode?: AppMode;
  language: Language;
  readOnly?: boolean;
}

const formatTime = (time: number) => {
  if (isNaN(time)) return "0:00";
  const minutes = Math.floor(time / 60);
  const seconds = Math.floor(time % 60);
  return `${minutes}:${seconds.toString().padStart(2, '0')}`;
};

const PlayerControls: React.FC<PlayerControlsProps> = ({
  state,
  onPlayPause,
  onNext,
  onPrev,
  onStop,
  onSeek,
  onVolumeChange,
  onFade,
  onFadeConfig,
  manualFadeDuration = 3, // Default value
  title,
  startTime,
  endTime,
  appMode = 'editing',
  language,
  readOnly = false
}) => {
  // Safe defaults if props are missing/zero
  const minVal = startTime || 0;
  const maxVal = (endTime && endTime > 0) ? endTime : (state.duration || 100);
  const t = translations[language];

  // Calculate width percentage relative to the custom range
  const duration = maxVal - minVal;
  const progress = Math.max(0, Math.min(duration, state.currentTime - minVal));
  const widthPct = duration > 0 ? (progress / duration) * 100 : 0;

  // Calculate remaining time relative to the Cut End
  const remaining = Math.max(0, maxVal - state.currentTime);

  const isLive = appMode === 'presentation';

  return (
    <div className={`h-full w-full flex items-center px-4 md:px-8 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.3)] ${readOnly ? 'pointer-events-none opacity-80' : ''}`}>

      {/* STOP BUTTON (Leftmost) - REDUCED SIZE */}
      <div className="mr-4 shrink-0">
          <button
            onClick={onStop}
            disabled={readOnly}
            className="flex items-center justify-center text-white rounded-full p-3 shadow-lg bg-red-600 hover:bg-red-500 shadow-red-900/50 transition-all transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
            title={t.stop_reset_tooltip}
          >
              <Square className="w-5 h-5 fill-current" />
          </button>
      </div>

      {/* Current Song Info (Left) */}
      <div className="w-1/4 hidden md:flex flex-col border-l border-slate-800 pl-4">
        <span className={`font-semibold truncate text-lg transition-colors ${state.isPlaying ? 'text-emerald-400' : 'text-orange-400'}`}>
            {title}
        </span>
        <span className="text-slate-400 text-sm">
            {state.isPlaying ? t.now_playing : t.waiting}
        </span>
      </div>

      {/* Main Controls (Center) */}
      <div className="flex-1 flex flex-col items-center justify-center gap-2 max-w-3xl mx-auto w-full px-2">

        {/* Buttons */}
        <div className="flex items-center gap-6">
          <button 
            onClick={onPrev}
            disabled={isLive || readOnly}
            className={`text-slate-400 transition-colors p-2 rounded-full active:scale-95 ${isLive || readOnly ? 'opacity-20 cursor-not-allowed' : 'hover:text-white hover:bg-slate-800'}`}
          >
            <SkipBack className="w-8 h-8" />
          </button>

          {/* PLAY BUTTON - NARROWER */}
          <button 
            onClick={onPlayPause}
            disabled={readOnly}
            className={`text-white rounded-full w-48 py-2.5 shadow-lg transition-all transform active:scale-95 flex items-center justify-between px-4 disabled:opacity-50 disabled:cursor-not-allowed ${
                state.isPlaying 
                ? 'bg-emerald-600 hover:bg-emerald-500 shadow-emerald-900/50' 
                : 'bg-indigo-600 hover:bg-indigo-500 shadow-indigo-900/50'
            }`}
          >
            {/* Elapsed Time - BIGGER FONT */}
            <span className="text-sm font-mono font-bold opacity-90 w-12 text-right tracking-tight">
                {formatTime(state.currentTime)}
            </span>

            {/* Icon */}
            {state.isPlaying ? (
              <Pause className="w-8 h-8 fill-current mx-auto" />
            ) : (
              <Play className="w-8 h-8 fill-current ml-1 mx-auto" />
            )}

            {/* Remaining Time - BIGGER FONT */}
            <span className="text-sm font-mono font-bold opacity-90 w-12 text-left tracking-tight">
                -{formatTime(remaining)}
            </span>
          </button>

          <button 
            onClick={onNext}
            disabled={readOnly}
            className="text-slate-400 hover:text-white transition-colors p-2 rounded-full hover:bg-slate-800 active:scale-95 disabled:opacity-20"
          >
            <SkipForward className="w-8 h-8" />
          </button>
        </div>

        {/* Progress Bar */}
        <div className="w-full flex items-center gap-3 text-xs font-mono text-slate-400">
          <span>{formatTime(state.currentTime)}</span>
          <div className={`flex-1 h-1.5 bg-slate-700 rounded-full cursor-pointer group relative ${readOnly ? 'pointer-events-none' : ''}`}>
             {/* Hit area for easier seeking */}
            <input 
              type="range"
              min={minVal}
              max={maxVal}
              value={state.currentTime}
              onChange={(e) => onSeek(Number(e.target.value))}
              disabled={readOnly}
              className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10 disabled:cursor-not-allowed"
            />
            {/* Visual Bar uses calculated percentage relative to the cut */}
            <div 
              className={`h-full rounded-full relative transition-colors ${state.isPlaying ? 'bg-emerald-500' : 'bg-orange-500'}`}
              style={{ width: `${widthPct}%` }}
            >
                <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full shadow opacity-0 group-hover:opacity-100 transition-opacity" />
            </div>
          </div>
          {/* Display End Time = MaxVal (Cut End) */}
          <span>{formatTime(maxVal)}</span>
        </div>
      </div>

      {/* Volume & Extras (Right) */}
      <div className="w-1/4 hidden md:flex justify-end items-center gap-4 pl-2">

        {/* Fade Button Group */}
        <div className="flex items-center gap-1 bg-slate-800 rounded-full p-1 border border-slate-700 relative">
            <button 
                onClick={onFade}
                disabled={!state.isPlaying || readOnly}
                className={`flex flex-col items-center justify-center w-10 h-10 rounded-full transition-all relative disabled:opacity-30 disabled:cursor-not-allowed
                    ${state.isFading 
                        ? 'bg-red-500/20 text-red-400 border border-red-500/50 shadow-[0_0_15px_rgba(239,68,68,0.3)] animate-pulse' 
                        : 'hover:bg-slate-700 group'
                    }`}
                title={t.fade_pause_tooltip}
            >
                <Wind className={`w-4 h-4 transition-colors ${state.isFading ? 'text-red-400' : 'text-slate-400 group-hover:text-emerald-400'}`} />
                {/* Visual Indicator of Seconds */}
                <span className={`absolute -top-2 -left-1 text-[8px] px-1 rounded-full border font-mono ${state.isFading ? 'bg-red-900/80 text-red-200 border-red-500/50' : 'bg-slate-950 text-emerald-400 border-slate-700'}`}>
                    {Math.round(manualFadeDuration)}s
                </span>
            </button>
            {onFadeConfig && (
                <button
                    onClick={onFadeConfig}
                    className="flex flex-col items-center justify-center w-8 h-8 rounded-full hover:bg-slate-700 text-slate-500 hover:text-white transition-colors disabled:opacity-30"
                    title="Configura durata Fade"
                    disabled={readOnly}
                >
                    <Settings className="w-3 h-3" />
                </button>
            )}
        </div>

        <div className="h-8 w-px bg-slate-800 mx-1"></div>

        {/* Volume - More compact but usable */}
        <div className="flex items-center gap-2 flex-1 max-w-[120px]">
            <button className="text-slate-400 shrink-0" disabled={readOnly}>
                {state.volume === 0 ? <VolumeX className="w-5 h-5"/> : <Volume2 className="w-5 h-5" />}
            </button>
            <input 
                type="range"
                min="0"
                max="1"
                step="0.05"
                value={state.volume}
                onChange={(e) => onVolumeChange(Number(e.target.value))}
                disabled={readOnly}
                className="w-full h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-3 [&::-webkit-slider-thumb]:h-3 [&::-webkit-slider-thumb]:bg-white [&::-webkit-slider-thumb]:rounded-full disabled:cursor-not-allowed"
            />
        </div>
      </div>
    </div>
  );
};

export default PlayerControls;

export interface Song {
  id: string;
  title: string;
  url: string;
  type?: 'audio' | 'separator'; // NEW: Distinguish audio from visual separators
  artist?: string;
  originalFileName?: string; // New field to store actual filename for export
  path?: string; // New field to store the full path/string from the playlist file
  // Editing parameters
  trimStart?: number; // Seconds
  trimEnd?: number;   // Seconds
  hasFadeOut?: boolean;
  fadeOutDuration?: number; // NEW: Custom duration in seconds
  customGain?: number; // 0.0 to 1.0 (default 1.0)
  note?: string; // Director's note
}

export interface SfxItem {
  id: string;
  label: string;
  url: string;
  originalFileName?: string; // Stores the filename for saving/loading
  path?: string; // New field to store the full path
  color?: string; // Optional color for the button
  // Editing parameters matching Song
  trimStart?: number;
  trimEnd?: number;
  hasFadeOut?: boolean;
  fadeOutDuration?: number; // NEW
  customGain?: number;
}

export interface PlayerState {
  isPlaying: boolean;
  currentTime: number;
  duration: number;
  volume: number;
  isFading?: boolean; // NEW: Track manual fade state
}

export type AppMode = 'editing' | 'presentation';

export type Language = 'it' | 'en';

