  const handlePlaylistLoaded = (newSongs: Song[], newSfx: SfxItem[], fileName?: string, path?: string, directory?: Directory, fromDisk: boolean = true) => {
    audioControls.hardReset();
    if (audioRef.current) audioRef.current.src = "";
