      AppGlobals.Playlistfilename = EstraiName(currentFull);
      AppGlobals.PlaylistLog = AppGlobals.Playlistpath + "Log_" + AppGlobals.Playlistfilename;

      setPickerState({ isOpen: true, target: 'save' });
