                {editingSfxIndex === null && !isNotesPinnedDesktop && (appMode === 'presentation' || !isAndroid) && (editingTarget as Song)?.type !== 'separator' && (
                    <div className="shrink-0 bg-slate-900 p-3 border-t border-slate-800">
